options.customCss:
/* =========================
   SKY Aesthetic UI
   ========================= */

:root,
.n8n-chat {

  /* ☁️ sky palette */
  --chat--color--primary: #74b9ff;
  --chat--color--primary-shade-50: #63aaf5;
  --chat--color--primary--shade-100: #4d96e6;

  --chat--color--secondary: #a29bfe;
  --chat--color-secondary-shade-50: #918af5;

  --chat--color-white: #ffffff;
  --chat--color-light: #f4f8ff;
  --chat--color-light-shade-50: #e9f0fb;
  --chat--color-light-shade-100: #dbe7f5;

  --chat--color-medium: #d6deea;
  --chat--color-dark: #4b5c74;
  --chat--color-disabled: #dbe2ec;
  --chat--color-typing: #6c7a89;

  /* layout */
  --chat--spacing: 1rem;
  --chat--border-radius: 1rem;
  --chat--transition-duration: 0.2s;
  --chat--font-family: 'Segoe UI', sans-serif;

  /* window */
  --chat--window--width: 380px;
  --chat--window--height: 600px;
  --chat--window--border-radius: 1.3rem;
  --chat--window--border: none;

  /* header */
  --chat--header--background: linear-gradient(135deg,#74b9ff,#a29bfe);
  --chat--header--color: white;
  --chat--header--padding: 1.2rem;

  --chat--heading--font-size: 1.25rem;

  /* body */
  --chat--body--background: #f4f8ff;
  --chat--footer--background: #f4f8ff;

  /* message bubble */
  --chat--message--font-size: 0.95rem;
  --chat--message--padding: 0.8rem 1rem;
  --chat--message--border-radius: 1rem;
  --chat--message--margin-bottom: 0.7rem;

  /* bot bubble */
  --chat--message--bot--background: #ffffff;
  --chat--message--bot--color: #4b5c74;

  /* user bubble */
  --chat--message--user--background: #74b9ff;
  --chat--message--user--color: white;

  --chat--message--pre--background: #eef3fb;

  /* toggle button */
  --chat--toggle--size: 60px;
  --chat--toggle--background: linear-gradient(135deg,#74b9ff,#a29bfe);
  --chat--toggle--hover--background: #63aaf5;
  --chat--toggle--active--background: #4d96e6;
  --chat--toggle--color: white;

  /* input */
  --chat--textarea--height: 50px;
  --chat--input--background: white;
  --chat--input--border-radius: 1rem;
  --chat--input--padding: 0.7rem;
  --chat--input--text-color: #4b5c74;

  /* button */
  --chat--button--border-radius: 0.8rem;

  --chat--button--background--primary: #74b9ff;
  --chat--button--background--primary--hover: #63aaf5;

  --chat--button--background--secondary: #a29bfe;
  --chat--button--background--secondary--hover: #918af5;

  /* send icon */
  --chat--input--send--button--color: #74b9ff;
  --chat--input--send--button--color-hover: #a29bfe;
}


/* bubble aesthetic */
.n8n-chat .chat-message {
  max-width: 70%;
  box-shadow: 0 3px 10px rgba(0,0,0,0.05);
  transition: 0.2s;
}

/* header gradient fix */
.n8n-chat .chat-header {
  background: linear-gradient(135deg,#74b9ff,#a29bfe) !important;
}

/* user bubble */
.n8n-chat .chat-message-user {
  background: #74b9ff !important;
  color: white !important;
}

/* bot bubble */
.n8n-chat .chat-message-bot {
  background: white !important;
}

/* glass effect */
.n8n-chat .chat-window {
  backdrop-filter: blur(6px);
  box-shadow: 0 8px 25px rgba(0,0,0,0.08);
}

/* input separator */
.n8n-chat .chat-input {
  border-top: 1px solid #e3ebf7;
}

/* send button animation */
.n8n-chat .chat-send-button:hover {
  transform: scale(1.08);
  transition: 0.2s;
}
